"""
MKT Original Language Commentary — Romans chapters 11–14
Run: python3 scripts/zc-original-romans-11-14.py

Source data used:
- data/interlinear/romans.json (chapters 11–14)
- data/translation/glossary-greek.json (key terms: G3466 μυστήριον dl=0, G4457 πώρωσις dl=0,
  G4138 πλήρωμα dl=0, G3050 λογικός dl=0, G3339 μεταμορφόω dl=0, G4964 συσχηματίζω dl=0,
  G3563 νοῦς dl=0, G1849 ἐξουσία dl=0, G26 ἀγάπη dl=3, G505 ἀνυπόκριτος dl=0,
  G1343 δικαιοσύνη dl=4, G4102 πίστις dl=3, G278 ἀμεταμέλητος dl=0, G342 ἀνακαίνωσις dl=0)
- data/translation/draft/mediating/romans.json (MKT text)
- data/commentary/ellicott/romans.json (philological reference for chapters 11–14)

Key decisions in this range:
- πώρωσις (G4457): "hardening" not "blindness"; medical term for calcification/callous tissue —
  the MKT follows this more precise rendering; noted at 11:25
- μυστήριον (G3466): Pauline technical sense — not a puzzle but a divine disclosure of
  something formerly hidden; noted at 11:25
- πλήρωμα (G4138): "fullness" as complete quota/number, not merely "abundance"; noted at 11:25
- λογικήν (G3050) at 12:1: the service that corresponds to what reason (logos) demands;
  MKT "reasonable/proper worship" preserves both senses
- μεταμορφόω (G3339) vs. συσχηματίζω (G4964) at 12:2: inner transformation vs.
  external pattern-conformity — the English verbs do not map the distinction precisely
- νοῦς (G3563) at 12:2: the faculty of moral discernment/understanding, not mere intellect
- ἐξουσία (G1849) at 13:1: granted authority/competency, not raw power (δύναμις)
- δικαιοσύνη (G1343, dl=4) at 14:17: behavioral/moral righteousness within the community,
  not the forensic justification sense dominant in chs. 1–8
- πίστις (G4102, dl=3) at ch. 14: personal conviction regarding disputed practices,
  a narrower use than the soteriological pistis of chs. 3–5; noted at 14:1, 14:22–23
- ἀμεταμέλητος (G278) at 11:29: "without afterthought," irrevocable — a legal/covenantal
  term applied to divine gifts and calling
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


ROMANS = {
  "11": {
    "1": '<p><strong>μὴ ἀπώσατο ὁ θεὸς τὸν λαὸν αὐτοῦ</strong> — The aorist middle <em>apōsato</em> (push away, reject) anticipates the expected conclusion from ch. 10\'s hard language. Paul\'s immediate counter-evidence is autobiographical: <em>καὶ γὰρ ἐγὼ Ἰσραηλίτης εἰμί</em> — "For I too am an Israelite." The <em>kai</em> is emphatic: I myself am exhibit A of an un-rejected Israelite. The three-part pedigree — seed of Abraham, tribe of Benjamin — mirrors the pattern of Phil 3:5, where the same credentials appear as grounds for confidence "in the flesh."</p>',
    "2": '<p><strong>οὐκ ἀπώσατο ὁ θεὸς τὸν λαὸν αὐτοῦ ὃν προέγνω</strong> — The relative clause <em>hon proegnō</em> (whom he foreknew) is the crux: election precedes any historical contingency, so rejection is structurally impossible. The verb <em>proginōskō</em> (G4267) in Paul never means mere foreknowledge in the informational sense; it means prior choice establishing relationship. Psalm 94:14 ("the Lord will not forsake his people") provides the ground; the Elijah episode provides the illustration.</p>',
    "3": '<p><strong>Κύριε, τοὺς προφήτας σου ἀπέκτειναν</strong> — The quotation follows 1 Kgs 19:10/14 (LXX). Elijah\'s complaint is the voice of prophetic despair: altars torn down, prophets killed, only I left (<em>κἀγὼ ὑπελείφθην μόνος</em>). Paul uses this as a type of the present crisis — the faithful remnant feels isolated, yet the divine answer will reveal otherwise.</p>',
    "4": '<p><strong>κατέλιπον ἐμαυτῷ ἑπτακισχιλίους ἄνδρας</strong> — The divine response uses the perfect <em>katelipon</em> (I have kept/reserved for myself): the remnant is not self-selected but divinely preserved. The dative <em>emautō</em> — for myself — establishes the remnant as God\'s possession, not simply survivors. The phrase "who have not bowed the knee to Baal" is a concrete behavioral test; the negative formulation (a knee not bent) serves as the criterion.</p>',
    "5": '<p><strong>λεῖμμα κατ᾽ ἐκλογὴν χάριτος γέγονεν</strong> — <em>Leimma</em> (G3005, remnant) picks up the Elijah language. <em>Kat᾽ eklogēn charitos</em> — according to election of grace: the genitive <em>charitos</em> qualifies the election. The perfect <em>gegonen</em> (has come to be and stands) marks the present reality of the remnant as established fact, not aspiration.</p>',
    "6": '<p><strong>εἰ δὲ χάριτι, οὐκέτι ἐξ ἔργων</strong> — A logical disjunction Paul has already established in ch. 4 with Abraham: grace and works are mutually exclusive bases for the same standing. <em>Epei hē charis ouketi ginetai charis</em> — otherwise grace is no longer grace. The <em>epei</em> (since/otherwise) clause states the consequence of mixing the two: the category dissolves. Paul\'s argument is analytic, not moral: by definition, grace-based election cannot be simultaneously works-based.</p>',
    "7": '<p><strong>τοῦτο οὗ ἐπιζητεῖ Ἰσραήλ, τοῦτο οὐκ ἐπέτυχεν</strong> — <em>Epizēteō</em> (G1934, seek earnestly) implies persistent pursuit. <em>Epitykhein</em> (to hit upon, attain, G2013) is the athletic-competition word for reaching the goal. Israel pursued but did not obtain; the elect obtained. <strong>οἱ δὲ λοιποὶ ἐπωρώθησαν</strong> — the rest were hardened: the divine passive of <em>pōroō</em> (G4456) — to calcify, to form a callous. The cognate noun <em>pōrōsis</em> (v.25) denotes the resulting condition.</p>',
    "8": '<p><strong>ἔδωκεν αὐτοῖς ὁ θεὸς πνεῦμα κατανύξεως</strong> — The citation blends Deut 29:4 and Isa 29:10 (LXX). <em>Katanyksis</em> (G2659) is a hapax in the NT: stupor, numbness, a word for the deep insensibility induced by divine judgment. In Isa 29:10 the parallel is "the spirit of deep sleep." Paul attributes the stupor to God\'s giving (<em>edōken</em>, aorist), not to Israel\'s self-infliction — consistent with the divine-passive hardening of v.7.</p>',
    "9": '<p><strong>Δαυὶδ λέγει· γενηθήτω ἡ τράπεζα αὐτῶν εἰς παγίδα</strong> — Ps 69:22–23 (LXX 68:22–23). The table (<em>trapeza</em>) that should provide sustenance becomes a snare (<em>pagis</em>) and a trap (<em>thēra</em>). Paul\'s use of David is deliberate: the Psalm is a suffering-righteous Psalm widely applied to Jesus in early Christianity (Ps 69:9 at John 2:17; 69:21 at Matt 27:34/John 19:29). The application to Israel\'s hardening draws from the same Psalm that elsewhere illuminates Christ\'s own rejection.</p>',
    "10": '<p><strong>σκοτισθήτωσαν οἱ ὀφθαλμοὶ αὐτῶν τοῦ μὴ βλέπειν</strong> — The continuation of Ps 69:23: darkened eyes and permanently bent backs. The articular infinitive <em>tou mē blepein</em> expresses purpose or result — eyes darkened so as not to see. <em>Dia pantos</em> (continually, always) indicates the sustained character of the judgment, not a temporary condition. The image of the bent back under load closes the citation with a picture of servitude.</p>',
    "11": '<p><strong>μὴ ἔπταισαν ἵνα πέσωσιν</strong> — The distinction is between <em>ptaiō</em> (G4417, to stumble) and <em>piptō</em> (G4098, to fall definitively). Did they stumble so as to fall irrecoverably? <em>Mē genoito</em> — by no means. The word <em>paraptōmati</em> (transgression, G3900) appears: their stumbling was a <em>paraptoōma</em> that occasioned Gentile inclusion. <em>Parazēlōsai</em> (G3863, to provoke to jealousy) picks up the motif from Deut 32:21 (cited at 10:19): Israel\'s jealousy of Gentile blessing is part of the restorative plan.</p>',
    "12": '<p><strong>εἰ δὲ τὸ παράπτωμα αὐτῶν πλοῦτος κόσμου</strong> — Paul constructs a <em>qal wachomer</em> (light-to-heavy) argument: if their failure (παράπτωμα) produces world-wealth, how much more will their <em>plērōma</em> produce? The word <em>plērōma</em> (G4138, fullness) here means their completion — their full inclusion. The contrast is παράπτωμα/ἥττημα (failure/defeat) against <em>plērōma</em>. The conclusion of the argument will come at v.26.</p>',
    "13": '<p><strong>ὑμῖν λέγω τοῖς ἔθνεσιν</strong> — Paul pivots to direct address to Gentile readers. He asserts his apostolic identity: <em>ἐφ᾽ ὅσον μέν εἰμι ἐγὼ ἐθνῶν ἀπόστολος</em> — inasmuch as I am apostle of the Gentiles. The present tense <em>eimi</em> is timeless. <em>δοξάζω τὴν διακονίαν μου</em> — I glorify my ministry: the verb <em>doxazō</em> does not mean boasting; it means to recognize and honor the worth of what has been entrusted.</p>',
    "14": '<p><strong>εἴ πως παραζηλώσω μου τὴν σάρκα</strong> — The optative <em>parazelōsō</em> (might provoke to jealousy) expresses contingent hope, not certainty. <em>Tēn sarka mou</em> — my flesh, i.e., my kinsmen according to biological descent (cf. 9:3). The chain of purpose: Paul\'s Gentile mission creates Gentile blessing → Gentile blessing provokes Jewish jealousy → jealousy leads some to salvation. Paul presents his Gentile apostolate as indirectly missionary to Israel.</p>',
    "15": '<p><strong>εἰ γὰρ ἡ ἀποβολὴ αὐτῶν καταλλαγὴ κόσμου</strong> — <em>Apobolē</em> (G580, casting away, rejection) is a rare word. <em>Katallagē</em> (G2643, reconciliation) appeared at 5:11; it denotes the restored relational status between God and the world. If their rejection produced reconciliation, what will their acceptance produce? The answer: <em>ζωὴ ἐκ νεκρῶν</em> — life from the dead. Whether this refers to eschatological resurrection or to a spiritual revival of unprecedented scale, Paul leaves the image to press the point: the scale is incomprehensible.</p>',
    "16": '<p><strong>εἰ δὲ ἡ ἀπαρχὴ ἁγία, καὶ τὸ φύραμα</strong> — <em>Aparkhē</em> (G536, firstfruit) and <em>phyrama</em> (G5445, lump of dough) draw on Num 15:20–21 where the dough offering consecrates the whole batch. The argument is one of representative holiness: the part that is holy sanctifies the whole. Paul applies the image in two registers: firstfruit/lump (temporal — the patriarchs sanctify the nation) and root/branches (organic — the root determines the character of what it supports).</p>',
    "17": '<p><strong>εἰ δέ τινες τῶν κλάδων ἐξεκλάσθησαν</strong> — <em>Exeklasthēsan</em> (were broken off, aorist passive) marks a completed act. The Gentile reader is addressed as a <em>ἀγριέλαιος</em> (G65, wild olive, hapax in NT) grafted in <em>ἐν αὐτοῖς</em> (among them, the remaining branches). The shared benefit is <em>τῆς ῥίζης τῆς πιότητος τῆς ἐλαίας</em> — the root of the fatness (richness) of the olive tree. <em>Piotēs</em> (G4096, fatness, richness) is agricultural: the root\'s nutrient supply feeds all grafted branches equally.</p>',
    "18": '<p><strong>μὴ κατακαυχῶ τῶν κλάδων</strong> — <em>Katakaukhaō</em> (G2620, to boast against, to exult over) is the specific wrong. The corrective is logical: <em>οὐ σὺ τὴν ῥίζαν βαστάζεις ἀλλ᾽ ἡ ῥίζα σέ</em> — you do not carry the root; the root carries you. The Gentile believer\'s continuance depends on the root (the patriarchal covenant/promise), not vice versa. The present tense <em>bastazeis/se</em> marks an ongoing structural reality.</p>',
    "19": '<p><strong>ἐρεῖς οὖν</strong> — Paul quotes the imagined Gentile interlocutor: "Branches were broken off so that I might be grafted in." The passive <em>exeklasthēsan</em> (were broken off) is used again; the purpose <em>hina egō enkentristhō</em> presumes the Gentile\'s grafting was the goal of Israel\'s breaking off. Paul will grant the premise in v.20 but challenge the inference.</p>',
    "20": '<p><strong>καλῶς· τῇ ἀπιστίᾳ ἐξεκλάσθησαν</strong> — <em>Kalōs</em> (well, rightly) concedes the factual claim: yes, broken off by unbelief. <strong>σὺ δὲ τῇ πίστει ἕστηκας</strong> — the dative of means: you stand by faith. The perfect <em>hestēkas</em> (you have stood and stand) marks a stable condition. The warning follows: <em>μὴ ὑψηλὰ φρόνει ἀλλὰ φοβοῦ</em> — do not think high thoughts but fear. <em>Hypsēla phronein</em> (to think loftily) is the same root as <em>hypselophrosynē</em> condemned in 12:16.</p>',
    "21": '<p><strong>εἰ γὰρ ὁ θεὸς τῶν κατὰ φύσιν κλάδων οὐκ ἐφείσατο</strong> — The aorist <em>epheisato</em> (spared, G5339): God did not spare the natural branches — those that belonged to the tree by origin. The argument is from the greater to the lesser: if not the natural, then certainly not you. The phrase <em>κατὰ φύσιν</em> (according to nature) reappears from 11:17 and anticipates the <em>παρὰ φύσιν</em> (against nature) of v.24 — the surprise of the Gentile grafting.</p>',
    "22": '<p><strong>ἴδε οὖν χρηστότητα καὶ ἀποτομίαν θεοῦ</strong> — Paul juxtaposes <em>chrēstotēs</em> (G5544, kindness/goodness) and <em>apotomia</em> (G663, severity/steepness; from <em>apotemnō</em>, to cut off sharply). The latter is a hapax in the NT; it denotes abruptness, the quality of an abrupt cut. The condition for continued Gentile standing: <em>ἐὰν ἐπιμένῃς τῇ χρηστότητι</em> — if you remain in the kindness. The conditional <em>ean</em> + present subjunctive marks genuine contingency: the standing is real but not unconditional in its continuation.</p>',
    "23": '<p><strong>ἐκεῖνοι δέ, ἐὰν μὴ ἐπιμένωσιν τῇ ἀπιστίᾳ, ἐγκεντρισθήσονται</strong> — The condition for Israel\'s re-grafting is removal of unbelief (<em>apistia</em>). The future passive <em>enkentristhēsontai</em> (will be grafted in) is the divine act awaiting the condition. The ground: <em>δυνατὸς γάρ ἐστιν ὁ θεὸς πάλιν ἐγκεντρίσαι αὐτούς</em> — God is able again to graft them in. <em>Dynatos</em> (G1415, powerful/able) emphasizes divine capacity against any human calculation that re-grafting is impossible.</p>',
    "24": '<p><strong>εἰ γὰρ σὺ ἐκ τῆς κατὰ φύσιν ἐξεκόπης ἀγριελαίου</strong> — Paul now explicitly names the Gentile situation as <em>παρὰ φύσιν</em> (against nature): the wild olive being grafted into the cultivated tree defies normal horticultural logic (the cultivated is grafted into rootstock, not the other direction). If the unnatural grafting happened, the natural re-grafting is <em>a fortiori</em> — <em>πολλῷ μᾶλλον</em> (how much more) — achievable. The argument closes the olive tree metaphor.</p>',
    "25": '<p><strong>οὐ θέλω ὑμᾶς ἀγνοεῖν, ἀδελφοί, τὸ μυστήριον τοῦτο</strong> — The disclosure formula (<em>ou thelō hymas agnoein</em> — I do not want you to be ignorant) marks a formal revelation. <em>Mystērion</em> (G3466) in Pauline usage is not a puzzle but something formerly hidden and now divinely disclosed (cf. 16:25–26; Col 1:26–27). The content: partial hardening (<em>πώρωσις ἀπὸ μέρους</em>) has come upon Israel until (<em>ἄχρι οὗ</em>) the fullness of the Gentiles enters.</p><p><em>Pōrōsis</em> (G4457, hardening) is the medical word for the formation of callous or calcified tissue — not blindness but insensibility to pressure. Its qualified character (<em>apo merous</em>, in part) is critical: not total and not permanent. <em>Plērōma tōn ethnōn</em> (fullness/completion of the Gentiles) has the sense of the full quota or number: the complete Gentile ingathering that precedes Israel\'s restoration.</p>',
    "26": '<p><strong>καὶ οὕτως πᾶς Ἰσραὴλ σωθήσεται</strong> — The adverb <em>houtōs</em> (in this way, thus) is key: it connects the mode of salvation to the process just described, not simply asserting a final result. "All Israel" is debated — whether it means the totality of ethnic Israel at a future point, or Israel as the full covenant people including Gentiles, or the full remnant elect of Israel through history. The citation follows: Isa 59:20–21 (LXX), where the Deliverer comes <em>ek Siōn</em> (from Zion) to turn ungodliness from Jacob. Paul adapts the LXX: the LXX has "for Zion\'s sake" (<em>heneken Siōn</em>); Paul\'s "from Zion" follows the MT more closely.</p>',
    "27": '<p><strong>καὶ αὕτη αὐτοῖς ἡ παρ᾽ ἐμοῦ διαθήκη</strong> — The covenant formula from Isa 59:21 blended with Isa 27:9: "this is my covenant with them, when I take away their sins." <em>Diathēkē</em> (G1242, covenant) is the LXX rendering of Hebrew <em>bĕrît</em>. The content is the removal of sins — the new covenant language of Jer 31:33–34 standing behind this whole cluster. Paul presents Israel\'s future restoration as a covenantal, not merely political, act.</p>',
    "28": '<p><strong>κατὰ μὲν τὸ εὐαγγέλιον ἐχθροὶ δι᾽ ὑμᾶς</strong> — The double <em>kata</em> structure draws the tension: according to the gospel they are enemies (the result of their rejection); according to election they are beloved (the result of the patriarchal covenant). <em>Di᾽ hymas</em> (for your sake) marks the Gentile benefit of their present enmity. <em>Di᾽ tous pateras</em> (because of the fathers): the patriarchal covenant is the unconditional ground of continued divine love — not current obedience or faith.</p>',
    "29": '<p><strong>ἀμεταμέλητα γὰρ τὰ χαρίσματα καὶ ἡ κλῆσις τοῦ θεοῦ</strong> — <em>Ametamelētos</em> (G278, irrevocable, without afterthought) is a legal/contractual term: a grant or call that cannot be recalled by the giver. Its semantic force is not emotional (God will not regret) but volitional and covenantal (God will not reverse). <em>Charismata</em> (G5486, gifts) here refers to the covenant gifts of 9:4–5 (adoption, glory, covenants, law, worship, promises, patriarchs); <em>klēsis</em> (G2821, calling) refers to Israel\'s election-summons.</p>',
    "30": '<p><strong>ὥσπερ γὰρ ὑμεῖς ποτε ἠπειθήσατε τῷ θεῷ</strong> — The past disobedience of the Gentiles (<em>ēpeithēsate</em>, aorist: a completed act) is now receiving mercy through Israel\'s disobedience. The syntax of vv.30–32 creates a set of interlocking <em>hōsper/houtōs</em> clauses (just as… so also) building toward the universal mercy statement of v.32. The pattern works by analogy of positions: Gentiles once disobedient → now mercy; Israel now disobedient → future mercy.</p>',
    "31": '<p><strong>οὕτως καὶ οὗτοι νῦν ἠπείθησαν τῷ ὑμετέρῳ ἐλέει</strong> — The unusual phrase <em>tō hymetero eleei</em> (by your mercy) — Israel\'s disobedience occasions mercy to Gentiles, and that mercy to Gentiles in turn occasions mercy to Israel. The dative <em>tō… eleei</em> is instrumental or causal. The double <em>nun</em> (now) in several manuscripts is difficult: "that they too now may receive mercy now." The repetition may be textual variation or a Pauline emphasis on the urgency and present timing of the merciful plan.</p>',
    "32": '<p><strong>συνέκλεισεν γὰρ ὁ θεὸς τοὺς πάντας εἰς ἀπείθειαν</strong> — <em>Synekleisen</em> (G4788, shut up together, confined) is a strong aorist: God has enclosed all in disobedience. The verb denotes imprisonment or enclosure — all are shut in to the same condition. The purpose: <em>ἵνα τοὺς πάντας ἐλεήσῃ</em> — so that he might show mercy to all. The double <em>tous pantas</em> (the all, all of them — with article) is emphatic. This does not assert universal salvation; it asserts universal need and universal availability of mercy, corresponding to the Gentile/Jew scope of chs. 1–3.</p>',
    "33": '<p><strong>Ὦ βάθος πλούτου καὶ σοφίας καὶ γνώσεως θεοῦ</strong> — The doxology breaks from argumentative prose into exclamation. The two adjectives are stacked with verbal nouns: <em>anexeraunēta</em> (G419, unsearchable, not subject to investigation — the root is the same as digging/mining: the riches cannot be mined out) and <em>anexichniastoi</em> (G421, past tracing out — from tracking footprints: his ways leave no trackable path). The genitives <em>sou</em> in vv.34–35 mark quotation; the nouns <em>krima</em> (G2917, judgment) and <em>hodos</em> (G3598, way/path) encompass both his judicial decisions and his operational methods.</p>',
    "34": '<p><strong>τίς γὰρ ἔγνω νοῦν κυρίου</strong> — Isa 40:13 (LXX). The rhetorical question expects the answer: no one. <em>Noux Kyriou</em> — the mind of the Lord. Paul uses <em>nous</em> (G3563) here in its sense of the reasoning capacity, the deliberative faculty. The parallel question — who has been his counselor (<em>symboulou</em>, G4825)? — extends the point: God\'s plan is not arrived at by consultation. The same Isaiah text will appear at 1 Cor 2:16 with a different argument.</p>',
    "35": '<p><strong>ἢ τίς προέδωκεν αὐτῷ, καὶ ἀνταποδοθήσεται αὐτῷ</strong> — Job 41:11 (LXX 41:3) or Isa 40:14. The commercial metaphor: who gave first, so that God must repay? <em>Proedōken</em> (G4272, give beforehand): no prior gift to God creates a debt. The future <em>antapodothēsetai</em> (will be repaid in return) is conditional on a prior gift — which the question establishes is impossible. Verse 35 closes the rhetorical triad with the economic impossibility of placing God under obligation.</p>',
    "36": '<p><strong>ὅτι ἐξ αὐτοῦ καὶ δι᾽ αὐτοῦ καὶ εἰς αὐτὸν τὰ πάντα</strong> — Three prepositional phrases deploy three distinct prepositions: <em>ek</em> (from/out of — source), <em>dia</em> (through — mediation), <em>eis</em> (into/toward — goal). All things have God as source, instrument, and telos. The Stoic formula <em>ex autou kai di᾽ autou kai eis auton</em> is adapted: Paul appropriates the cosmological structure but gives it a personal subject. The doxology <em>autō hē doxa eis tous aiōnas</em> closes the doctrinal argument of chs. 9–11.</p>'
  },
  "12": {
    "1": '<p><strong>παρακαλῶ οὖν ὑμᾶς, ἀδελφοί, διὰ τῶν οἰκτιρμῶν τοῦ θεοῦ</strong> — The <em>oun</em> (therefore) is the structural hinge linking chs. 1–11 to chs. 12–16: the entire doctrinal argument grounds the ethical appeal. <em>Parakaleō</em> (G3870, urge, exhort) is softer than command; the motivation clause <em>dia tōn oiktirmōn</em> (through the mercies of God) invokes chs. 9–11\'s mercy-theme. <em>Oiktirmos</em> (G3628, compassion) is plural here — the many acts of divine mercy form the basis of the appeal.</p><p><strong>παραστῆσαι τὰ σώματα ὑμῶν θυσίαν ζῶσαν</strong> — The sacrificial vocabulary is deliberate: <em>paristēmi</em> (G3936, to present/offer, the term for presenting animals at the altar), <em>thysia</em> (G2378, sacrifice). But the sacrifice is <em>zōsan</em> (living) — not slaughtered. <em>Hagian euareston tō theō</em> (holy and pleasing to God) picks up the Levitical acceptability language transferred to bodily offering. <strong>τὴν λογικὴν λατρείαν ὑμῶν</strong> — <em>Logikēn</em> (G3050) derives from <em>logos</em>: what corresponds to reason, the rational/verbal offering. It is distinguished from external cultic rites (<em>latreia</em>, G2999, temple service) that are now replaced by embodied, rational devotion.</p>',
    "2": '<p><strong>μὴ συσχηματίζεσθε τῷ αἰῶνι τούτῳ</strong> — <em>Syschēmatizō</em> (G4964) denotes conforming to an external pattern, shaping oneself to a mold. <em>Aión</em> (G165) here is the present age in its temporal and moral character — the existing order with its values, ambitions, and assumptions. <strong>ἀλλὰ μεταμορφοῦσθε τῇ ἀνακαινώσει τοῦ νοός</strong> — <em>Metamorphoō</em> (G3339, transform) differs: it describes an inward structural change, not merely surface alteration. <em>Anakainōsis</em> (G342, renewal/renovation) is a hapax cognate: the noun refers to the process of making new from within. The agent is <em>nous</em> (G3563, mind/moral reason): the renewed faculty of discernment makes possible the proving of God\'s will.</p><p><strong>εἰς τὸ δοκιμάζειν ὑμᾶς τί τὸ θέλημα τοῦ θεοῦ</strong> — <em>Dokimazein</em> (G1381, to test/prove/discern) is the word for assaying metal: the renewed mind is capable of accurate moral discernment. The three-fold description of God\'s will — <em>to agathon kai euareston kai teleion</em> (good, pleasing, and perfect) — is chiastic with 12:1: what is offered must be <em>euareston</em> (pleasing); what is discerned is the same <em>euareston</em> will.</p>',
    "3": '<p><strong>μὴ ὑπερφρονεῖν παρ᾽ ὃ δεῖ φρονεῖν</strong> — <em>Hyperphronein</em> (to think above what one ought) and <em>sōphronein</em> (to think soberly) both derive from <em>phronein</em> (to think, to set one\'s mind). Paul creates a word-play: the excess of thinking highly must be restrained to the measure. The measure is <em>κατὰ τὸ μέτρον τῆς πίστεως ὃ ἐμέρισεν ὁ θεός</em> — the measure of faith God distributed. The <em>metron</em> (measure) is not self-evaluated; God distributes (<em>emerisen</em>, aorist) it. This grounds humility not in self-deprecation but in accurate calibration against the divine allotment.</p>',
    "4": '<p><strong>ἐν γὰρ τῷ σώματι τῷ ἑνὶ πολλὰ μέλη ἔχομεν</strong> — The body (<em>sōma</em>, G4983) metaphor will be developed extensively at 1 Cor 12. Here it is compressed: one body, many members (<em>melē</em>, G3196), different functions (<em>praxis</em>, G4234, action/activity). The physical body is the analogy, not allegory: the argument depends on the observable fact of functional differentiation within organic unity.</p>',
    "5": '<p><strong>οἱ πολλοὶ ἓν σῶμά ἐσμεν ἐν Χριστῷ</strong> — <em>Hoi polloi</em> (the many) becomes <em>hen sōma</em> (one body): plurality does not dissolve but is constituted as unity <em>en Christō</em>. The phrase <em>to de kath᾽ heis allelōn melē</em> (each one members of one another) expresses mutual belonging: the members are not merely parts of a whole but relational participants — belonging <em>to each other</em>.</p>',
    "6": '<p><strong>ἔχοντες δὲ χαρίσματα κατὰ τὴν χάριν τὴν δοθεῖσαν ἡμῖν διάφορα</strong> — <em>Charismata</em> (G5486, gifts of grace) differ from one another: <em>diaphora</em> (different, various). The standard for exercise is <em>kata tēn analogian tēs pisteōs</em> (according to the proportion of faith): <em>analogia</em> (G356, proportion, ratio) is a mathematical term. Prophecy is to be exercised in proportion to one\'s measure of faith — the output calibrated to the input.</p>',
    "7": '<p><strong>εἴτε διακονίαν, ἐν τῇ διακονίᾳ</strong> — The gift list is structured by <em>eite</em> (either… or) + noun + activity. <em>Diakonia</em> (G1248, service/ministry) — in service; <em>didaskalia</em> (G1319, teaching) — in teaching. The parallel structure in each clause: name the gift, then describe its exercise. The list is not exhaustive (cf. 1 Cor 12) but illustrative of the principle that each gift has a corresponding mode of exercise.</p>',
    "8": '<p><strong>ὁ μεταδιδοὺς ἐν ἁπλότητι</strong> — <em>Metadidous</em> (the one sharing/giving, G3330): giving is a charisma here. <em>Haplotēs</em> (G572, simplicity/sincerity) — without ulterior motive or self-promotion. <em>Proïstamenos</em> (G4291, leader/one who stands before): leadership exercised <em>en spoudē</em> (with diligence). <em>Eleon</em> (G1656, mercy, compassionate act) — mercy shown <em>en hilarotēti</em> (G2432, hilarity/cheerfulness, the root of English "hilarious"): the etymology preserves the connection — mercy given without resentment.</p>',
    "9": '<p><strong>ἡ ἀγάπη ἀνυπόκριτος</strong> — The paraenesis begins with a nominative absolute, a statement about love functioning as a heading. <em>Agapē</em> (G26, dl=3) is the covenant-loyalty, self-giving form of love. <em>Anypokritos</em> (G505, without hypocrisy, unfeigned) is a single compound adjective: <em>a-</em> (not) + <em>hypokrinō</em> (to play a role, from theater). Love that is not theatrical performance.</p><p><strong>ἀποστυγοῦντες τὸ πονηρόν, κολλώμενοι τῷ ἀγαθῷ</strong> — The participles <em>apostygountes</em> (abhorring, G655 — <em>apo</em> + <em>stygein</em>, to hate with a shudder) and <em>kollōmenoi</em> (clinging, G2853, a word for adhesion/gluing) are in sharp contrast. The strength of the language: not merely avoiding evil but detesting it; not merely pursuing good but adhering to it.</p>',
    "10": '<p><strong>τῇ φιλαδελφίᾳ εἰς ἀλλήλους φιλόστοργοι</strong> — <em>Philadelphia</em> (G5360, brotherly love) and <em>philostorgos</em> (G5387, tenderly devoted — as family affection): Paul applies family-affection vocabulary to the community. <em>Tē timē allēlous proēgoumenoi</em> — in honor outstripping one another: the verb <em>proēgeomai</em> (G4285) is competitive — each racing to honor the other first. The competitive spirit is directed toward deferring rather than receiving honor.</p>',
    "11": '<p><strong>τῇ σπουδῇ μὴ ὀκνηροί, τῷ πνεύματι ζέοντες</strong> — <em>Oknēros</em> (G3636, sluggish, lazy): not negligent in eagerness. <em>Zeontes tō pneumati</em> (burning/boiling in spirit, G2204): the thermal metaphor for spiritual fervor — the same word for boiling liquid. Whether <em>pneuma</em> here is the Holy Spirit or the human spirit is debated; the dative of sphere (in spirit) suggests it is the sphere of operation. <em>Tō kyriō douleuontes</em> (serving the Lord): the present participle marks ongoing service as the context of zeal.</p>',
    "12": '<p><strong>τῇ ἐλπίδι χαίροντες, τῇ θλίψει ὑπομένοντες</strong> — Three datives of sphere, three participles: rejoicing in hope, enduring in affliction, persevering in prayer. <em>Hypomonē</em> (the noun root behind <em>hypomenontes</em>, G5278) is not passive resignation but active endurance under load. <em>Prosedreountes tē proseuchē</em> (G4342, continuing steadfastly in prayer): the compound <em>pros</em> + <em>hedraios</em> (firmly seated before) — holding one\'s position at prayer.</p>',
    "13": '<p><strong>ταῖς χρείαις τῶν ἁγίων κοινωνοῦντες</strong> — <em>Koinōneō</em> (G2841, to share in/contribute to): the verb behind <em>koinōnia</em>. The object <em>tais khreiais</em> (the needs) of the saints — practical need-sharing is part of the community\'s identity, not an optional charity. <em>Tēn philoxenian diōkontes</em> (G5381, pursue hospitality): <em>diōkō</em> is the pursuit-word, normally used for chasing an enemy or a prize. Hospitality is to be pursued, not merely practiced when convenient.</p>',
    "14": '<p><strong>εὐλογεῖτε τοὺς διώκοντας ὑμᾶς</strong> — The echo of Q-tradition (Matt 5:44 // Luke 6:28) is close enough that Paul may be quoting dominical teaching without identifying it as such. The present tense <em>eulogein</em> (to bless, speak well of) and the command not to curse (<em>mē katarasthe</em>) cover the same action from both sides. The ones who pursue/persecute (<em>diōkontas</em>) are the same word as "pursue" in v.13: the linguistic echo sharpens the irony.</p>',
    "15": '<p><strong>χαίρειν μετὰ χαιρόντων, κλαίειν μετὰ κλαιόντων</strong> — Two infinitives used as imperatives (asyndeton — no connecting particle). <em>Klaiein</em> (to weep, G2799) with those who weep: Paul places this second, perhaps because it is less natural. Empathic sorrow with the grieving requires more self-transcendence than shared joy. The emotional mirroring expected of the community is comprehensive — celebration and grief.</p>',
    "16": '<p><strong>τὸ αὐτὸ εἰς ἀλλήλους φρονοῦντες</strong> — <em>To auto phronein</em> (to think the same thing toward one another): the phrase does not mandate intellectual uniformity but the same orientation of mutual regard. <strong>μὴ τὰ ὑψηλὰ φρονοῦντες ἀλλὰ τοῖς ταπεινοῖς συναπαγόμενοι</strong> — <em>Hypsēla phronein</em> (to think high/lofty thoughts) versus <em>tois tapeinois synapagomenoi</em> (carried away with the lowly). <em>Tapeinoi</em> (G5011) may mean humble people or low social position — both senses apply. <em>Synapagō</em> (G4879, to be carried away with/toward) suggests being drawn into their world, not merely condescending to help them.</p>',
    "17": '<p><strong>μηδενὶ κακὸν ἀντὶ κακοῦ ἀποδιδόντες</strong> — <em>Anti</em> (in exchange for): the tit-for-tat structure of retribution is the thing prohibited. <em>Apodidōmi</em> (G591, to give back) used of rendering what is owed: treating evil as something that creates an obligation to return evil. <strong>προνοούμενοι καλὰ ἐνώπιον πάντων ἀνθρώπων</strong> — providing for good (<em>pronoumenoi</em>, G4306, to think beforehand/plan for) in the sight of all people: visible integrity as a community value, not merely private virtue.</p>',
    "18": '<p><strong>εἰ δυνατόν, τὸ ἐξ ὑμῶν, μετὰ πάντων ἀνθρώπων εἰρηνεύοντες</strong> — Two qualifications: <em>ei dynaton</em> (if possible — not always possible) and <em>to ex hymōn</em> (as far as it is from you — contingent on your own side). Paul is realistic: peace with all people is the aim, but both conditions recognize that the will of others may make it unachievable. The imperative mood of <em>eirēneuontes</em> applies to what lies within the community\'s own power.</p>',
    "19": '<p><strong>μὴ ἑαυτοὺς ἐκδικοῦντες, ἀγαπητοί</strong> — <em>Ekdikeō</em> (G1556, to vindicate, avenge) — the reflexive construction: do not avenge yourselves. <em>Agapētoi</em> (beloved) is an unusual address in Paul\'s ethical sections; it signals the warmth behind the prohibition. <strong>δότε τόπον τῇ ὀργῇ</strong> — give place to the wrath: <em>orgē</em> with the article may indicate God\'s wrath specifically. The citation follows from Deut 32:35: "mine is the vengeance, I will repay." <em>Kyrios</em> (Lord) — in the LXX this is YHWH; Paul applies the same principle to Christian conduct.</p>',
    "20": '<p><strong>ἐὰν πεινᾷ ὁ ἐχθρός σου, ψώμιζε αὐτόν</strong> — Prov 25:21–22 (LXX). The feeding and giving drink are the counter-action to enmity. <strong>ἄνθρακας πυρὸς σωρεύσεις ἐπὶ τὴν κεφαλὴν αὐτοῦ</strong> — <em>Anthrakas pyros</em> (coals of fire): the image is debated — shame (heat on the head as a sign of burning remorse), an Egyptian ritual of repentance, or simply the effect that kindness has in exposing and intensifying the enemy\'s guilt. The Proverbs context suggests the purpose is the enemy\'s transformation, not punishment: the LXX adds "and the Lord will reward you," framing the act as generosity.</p>',
    "21": '<p><strong>μὴ νικῶ ὑπὸ τοῦ κακοῦ, ἀλλὰ νίκα ἐν τῷ ἀγαθῷ τὸ κακόν</strong> — The closing aphorism is chiastic: <em>nikō/nikō</em> (overcome) and <em>kakō/kalon</em> (evil/good). The verb <em>nikaō</em> (G3528, to conquer, used of military victory) frames the ethical life as agonistic: evil is a conquering force; the response is counter-conquest through good. The preposition <em>en</em> (in/by means of) marks the instrument: the weapon against evil is good itself.</p>'
  },
  "13": {
    "1": '<p><strong>πᾶσα ψυχὴ ἐξουσίαις ὑπερεχούσαις ὑποτασσέσθω</strong> — <em>Pasa psykhē</em> (every soul) is a Hebraism for every person. <em>Exousiai hyperekhousin</em> — governing authorities (<em>exousia</em>, G1849, granted authority/competency, not raw power; <em>hyperekhousa</em>, G5242, excelling/surpassing — those set above). <em>Hypotassesthō</em> (G5293, be subject to) is the military-administrative word for placing oneself in proper order under a command structure — not blind obedience but structural recognition of rank.</p><p><strong>οὐ γάρ ἐστιν ἐξουσία εἰ μὴ ὑπὸ θεοῦ, αἱ δὲ οὖσαι ὑπὸ θεοῦ τεταγμέναι εἰσίν</strong> — The perfect passive <em>tetagmenai eisin</em> (have been arranged by God and remain so): the divine ordering is presented as a standing reality. The ground of the political submission is not the virtue of rulers but the divine ordering. The argument is structural, not evaluative.</p>',
    "2": '<p><strong>ὁ ἀντιτασσόμενος τῇ ἐξουσίᾳ τῇ τοῦ θεοῦ διαταγῇ ἀνθέστηκεν</strong> — <em>Antitassomenos</em> (G498, to set oneself against) versus <em>diatagē</em> (G1296, ordinance/ordering). The one resisting the authority resists the divine ordering (<em>anthestēken</em>, perfect: has taken a stand against and remains in resistance). <em>Anthistēmi</em> (G436) used in perfect marks a stable condition of opposition. The consequence: <em>heautois krima lēmpsontai</em> — they will receive judgment upon themselves.</p>',
    "3": '<p><strong>οἱ γὰρ ἄρχοντες οὐκ εἰσὶν φόβος τῷ ἀγαθῷ ἔργῳ ἀλλὰ τῷ κακῷ</strong> — The magistrate (<em>arkhōn</em>, G758, ruler, chief) is described by function: terror to evil, not to good. The idealized description (rulers commend good conduct, punish bad) is not a naïve claim that all rulers behave this way, but an account of the institutional role rulers are designed to fulfill — the norm against which aberrations are measured. <em>Theleis de mē phobeisthai tēn exousian</em> — do you wish not to fear? Then do good.</p>',
    "4": '<p><strong>θεοῦ γὰρ διάκονός ἐστιν σοὶ εἰς τὸ ἀγαθόν</strong> — <em>Diakonos</em> (G1249, servant/minister): the ruler is described as God\'s servant (<em>diakonos</em>, not <em>doulos</em> — a minister of a function, not a personal slave). The same term appears for the Christian minister at 15:8. <strong>τὴν μάχαιραν φορεῖ</strong> — bearing the sword (<em>makhaira</em>, G3162, the short sword of execution and police power). The present tense <em>phorei</em> (G5409, habitually wear/bear) marks the sword as permanent equipment of the office. <em>Ekdikos eis orgēn</em> (G1558, avenger for wrath) — the civil authority legitimately executes the divine wrath deferred by private persons in 12:19.</p>',
    "5": '<p><strong>ὑποτάσσεσθαι οὐ μόνον διὰ τὴν ὀργὴν ἀλλὰ καὶ διὰ τὴν συνείδησιν</strong> — Two grounds for submission: fear of punishment (<em>dia tēn orgēn</em>) and conscience (<em>syneidēsis</em>, G4893). <em>Syneidēsis</em> is the faculty of moral self-assessment, the reflexive awareness of one\'s own moral status. Paul elevates submission from mere self-interest (avoiding punishment) to moral obligation arising from conscience. The second ground implies the first is insufficient motivation by itself.</p>',
    "6": '<p><strong>διὰ τοῦτο γὰρ καὶ φόρους τελεῖτε</strong> — <em>Phorous telein</em> (G5411, G5055, to pay tribute/taxes): tax payment is the concrete application of the submission principle. <em>Leitourgoi gar theou eisin</em> — for they are ministers of God (<em>leitourgos</em>, G3011, a word from public service and cultic ministry). The term elevates the civil magistrate to the status of public servant in the divine economy. <em>Eis auto touto proskarterountes</em> (persisting in this very thing): the participle suggests the continuous, full-time character of governing service.</p>',
    "7": '<p><strong>ἀπόδοτε πᾶσιν τὰς ὀφειλάς</strong> — <em>Apodote</em> (G591, give back/render): the concept of debt-payment reappears from v.8. The fourfold list — <em>phoros</em> (tribute, direct tax on property), <em>telos</em> (G5056, indirect tax/toll on goods), <em>phobos</em> (G5401, fear/respect), <em>timē</em> (G5092, honor) — exhausts the categories of civic obligation. The last two are not financial but relational. The verse marks the outer limit of civic obligation before the greater debt is named in v.8.</p>',
    "8": '<p><strong>μηδενὶ μηδὲν ὀφείλετε εἰ μὴ τὸ ἀλλήλους ἀγαπᾶν</strong> — The wordplay on <em>opheilē</em> (debt, G3782) from v.7: after paying all other debts, one debt remains permanently outstanding — mutual love. The infinitive <em>agapan</em> (to love) is the content of the single perpetual obligation. <strong>ὁ γὰρ ἀγαπῶν τὸν ἕτερον νόμον πεπλήρωκεν</strong> — the one loving the other has fulfilled the law. The perfect <em>peplērōken</em> (has fulfilled and the fulfillment stands) is strong: love is not partial-law but complete-law fulfillment.</p>',
    "9": '<p><strong>τὸ γὰρ Οὐ μοιχεύσεις, Οὐ φονεύσεις, Οὐ κλέψεις, Οὐκ ἐπιθυμήσεις</strong> — Paul follows a non-Masoretic order (7th, 6th, 8th, 10th commandment) — the same sequence found in some LXX manuscripts, Luke 18:20, and James 2:11. The order reflects a textual tradition Paul knew. <strong>ἀνακεφαλαιοῦται ἐν τῷ λόγῳ τούτῳ</strong> — <em>Anakephalaioo</em> (G346, to sum up under one head) is a rhetorical term from the summary recapitulation at the end of an argument. The commandments are not repealed but gathered under a single head: love your neighbor as yourself (Lev 19:18).</p>',
    "10": '<p><strong>ἡ ἀγάπη τῷ πλησίον κακὸν οὐκ ἐργάζεται</strong> — <em>Plēsion</em> (G4139, neighbor — the one near) receives the practical definition: love works no harm to the neighbor. The negative is absolute: <em>ouk ergazetai</em> (does not work/produce). <strong>πλήρωμα οὖν νόμου ἡ ἀγάπη</strong> — love is the fullness (<em>plērōma</em>) of law. The same word used at 11:12, 25 for the fullness of Gentiles: here love brings the law to its completion, not by abolishing it but by filling it out completely.</p>',
    "11": '<p><strong>εἰδότες τὸν καιρόν, ὅτι ὥρα ἤδη ὑμᾶς ἐξ ὕπνου ἐγερθῆναι</strong> — <em>Kairos</em> (G2540, the appointed time, the decisive moment) — different from <em>chronos</em> (clock-time). <em>Hōra</em> (G5610, hour) narrows the urgency: the moment for waking from sleep has arrived. <em>Nyn gar eggyteron hēmōn hē sōtēria ē hote episteu samen</em> — our salvation is nearer now than when we believed. <em>Engyteron</em> (nearer, comparative) marks progressive proximity. <em>Sōtēria</em> (G4991, salvation) here has an eschatological referent: the final deliverance, not the initial reception of the gospel.</p>',
    "12": '<p><strong>ἡ νὺξ προέκοψεν, ἡ δὲ ἡμέρα ἤγγικεν</strong> — <em>Proekopsen</em> (G4298, has advanced, is far gone — aorist): the night has progressed toward its end. <em>Ēngiken</em> (G1448, has drawn near — perfect): the day stands near and remains so. The metaphor coordinates with the sleep/waking of v.11. <strong>ἀποθώμεθα οὖν τὰ ἔργα τοῦ σκότους, ἐνδυσώμεθα δὲ τὰ ὅπλα τοῦ φωτός</strong> — The clothing metaphor: <em>apothōmetha</em> (throw off, strip off) the works of darkness; <em>endysōmetha</em> (put on, clothe ourselves with) the armor of light. The military <em>hopla</em> (G3696, weapons/arms) rather than mere clothing heightens the agonistic framing.</p>',
    "13": '<p><strong>ὡς ἐν ἡμέρᾳ εὐσχημόνως περιπατήσωμεν</strong> — <em>Euschēmonōs</em> (G2156, becomingly, with good form): the word has social connotations — behavior that conforms to recognized standards of propriety. Daylight makes conduct visible and accountable. The three paired vices — <em>kōmois kai methais</em> (carousing and drunkenness), <em>koitais kai aselgeiais</em> (sexual immorality and licentiousness), <em>eridi kai zēlō</em> (strife and jealousy) — pair external excess with its social destructive counterpart.</p>',
    "14": '<p><strong>ἐνδύσασθε τὸν κύριον Ἰησοῦν Χριστόν</strong> — The positive clothing command names the garment explicitly: the Lord Jesus Christ. <em>Endysasthe</em> (G1746, aorist middle: clothe yourselves) — the same verb as v.12\'s putting on the armor of light. Here the armor is identified with a person. The command picks up the baptismal imagery of Gal 3:27 ("all who were baptized into Christ have put on Christ"). <strong>καὶ τῆς σαρκὸς πρόνοιαν μὴ ποιεῖσθε εἰς ἐπιθυμίας</strong> — <em>Sarx</em> (G4561) here carries the Pauline ethical sense: the fleshly nature with its desires (<em>epithymiai</em>). <em>Pronoia</em> (G4307, forethought, provision): do not make provision for the flesh\'s desires — do not plan for or supply what the fleshly impulses demand.</p>'
  },
  "14": {
    "1": '<p><strong>τὸν δὲ ἀσθενοῦντα τῇ πίστει προσλαμβάνεσθε</strong> — <em>Astheneō</em> (G770, to be weak): the weakness is in <em>tē pistei</em> (in faith). Here <em>pistis</em> (G4102, dl=3) carries a narrower sense than the soteriological pistis of chs. 3–5: it is the personal conviction that enables freedom from scrupulosity regarding food and days. The weak in faith lack this settled conviction, not saving faith. <em>Proslambano</em> (G4355, receive/welcome alongside) — to take someone into one\'s company, not merely to tolerate them. <strong>μὴ εἰς διακρίσεις διαλογισμῶν</strong> — not for judging disputed thoughts: <em>diakrisis</em> (G1253) is discrimination/judging; <em>dialogismoi</em> (G1261, calculations, reasonings) — not for the purpose of disputing over their scruples.</p>',
    "2": '<p><strong>ὁ μὲν πιστεύει φαγεῖν πάντα</strong> — <em>Pisteuei</em> here means believes/is convinced (personal conviction, not saving faith). Eating all things versus eating only vegetables: the background is Jewish dietary law and the difficulty of securing ritually pure meat in Gentile contexts (cf. 1 Cor 8–10). The strong believer\'s freedom extends to <em>panta</em> (all things); the weak person eats <em>lakhana</em> (G3001, vegetables/herbs).</p>',
    "3": '<p><strong>ὁ ἐσθίων τὸν μὴ ἐσθίοντα μὴ ἐξουθενείτω</strong> — <em>Exoutheneō</em> (G1848, to treat as nothing, despise): the eater must not despise the abstainer. <strong>ὁ δὲ μὴ ἐσθίων τὸν ἐσθίοντα μὴ κρινέτω</strong> — the abstainer must not judge (<em>krinō</em>, G2919) the eater. The two wrongs are different: despising (looking down from strength) and judging (condemning from scruple). Both are corrected by the same ground: <em>ὁ θεὸς γὰρ αὐτὸν προσελάβετο</em> — God has welcomed him.</p>',
    "4": '<p><strong>σὺ τίς εἶ ὁ κρίνων ἀλλότριον οἰκέτην</strong> — <em>Allotrios oiketēs</em> (another person\'s household servant): to judge another person\'s slave is to intrude into a master-servant relationship that is not yours. <em>Oiketēs</em> (G3610, house-slave) rather than <em>doulos</em>: the domestic context emphasizes the master\'s exclusive prerogative of evaluation. <strong>τῷ ἰδίῳ κυρίῳ στήκει ἢ πίπτει</strong> — he stands or falls before his own master. <em>Stēkō</em> (G4739, stand firm) as perfect of <em>histēmi</em>: present standing. <strong>σταθήσεται δέ</strong> — he will stand: the divine passive asserts God\'s capacity to make the servant stand despite the skepticism of the judging party.</p>',
    "5": '<p><strong>ὃς μὲν κρίνει ἡμέραν παρ᾽ ἡμέραν, ὃς δὲ κρίνει πᾶσαν ἡμέραν</strong> — The day-observance dispute: one person judges (discerns, considers, G2919) one day above another; another judges every day alike. The background likely includes Sabbath and feast-day observance. <strong>ἕκαστος ἐν τῷ ἰδίῳ νοῒ πληροφορείσθω</strong> — each person be fully persuaded in their own mind (<em>plērophoreō</em>, G4135, to fully convince, fill with certainty). <em>Nous</em> (G3563) is the moral reasoning faculty. The responsibility for conviction rests with each individual before God, not with the community\'s consensus.</p>',
    "6": '<p><strong>ὁ φρονῶν τὴν ἡμέραν κυρίῳ φρονεῖ</strong> — <em>Phronō</em> (G5426, to think, to regard with mindful attention) — the one observing the day observes it to the Lord. The parallel construction: eating/abstaining, both directed to the Lord with thanksgiving (<em>eukharisteō</em>, G2168). The criterion for both is the same: orientation toward the Lord and giving of thanks. The content of the practice differs; the Lord-directedness does not.</p>',
    "7": '<p><strong>οὐδεὶς γὰρ ἡμῶν ἑαυτῷ ζῇ καὶ οὐδεὶς ἑαυτῷ ἀποθνῄσκει</strong> — The principle underlying the Lord-orientation of v.6: no one lives to themselves, no one dies to themselves. <em>Heautō</em> (dative of benefit — for himself alone): life and death are not self-enclosed transactions. The verse is a general anthropological claim before the Christological ground is given in vv.8–9.</p>',
    "8": '<p><strong>ἐάν τε γὰρ ζῶμεν, τῷ κυρίῳ ζῶμεν, ἐάν τε ἀποθνῄσκωμεν, τῷ κυρίῳ ἀποθνῄσκομεν</strong> — The dative <em>tō kyriō</em> in all four clauses: to the Lord we live, to the Lord we die. <em>Eante</em> (whether) creates the exhaustive disjunction. <strong>ἐάν τε οὖν ζῶμεν ἐάν τε ἀποθνῄσκωμεν, τοῦ κυρίου ἐσμέν</strong> — the conclusion: we are the Lord\'s. The genitive <em>tou kyriou</em> marks ownership/belonging — existence in either state is possession by the Lord.</p>',
    "9": '<p><strong>εἰς τοῦτο γὰρ Χριστὸς ἀπέθανεν καὶ ἔζησεν</strong> — The aorist-then-aorist: <em>apethanen</em> (died) and <em>ezēsen</em> (lived/came to life — a constative aorist for the resurrection). The purpose: <em>ἵνα καὶ νεκρῶν καὶ ζώντων κυριεύσῃ</em> — so that he might be Lord of both dead and living. The scope of Christ\'s lordship is total: death and resurrection together establish his dominion over all human states. The present-tense ethical claim of ch. 14 is grounded in this Christological fact.</p>',
    "10": '<p><strong>σὺ δὲ τί κρίνεις τὸν ἀδελφόν σου; ἢ καὶ σὺ τί ἐξουθενεῖς τὸν ἀδελφόν σου</strong> — Two questions — one to the judger, one to the despiser (reversing the order of v.3 to address each party directly). Both actions are delegitimized by the ground that follows: <strong>πάντες γὰρ παραστησόμεθα τῷ βήματι τοῦ θεοῦ</strong> — all of us will stand before God\'s judgment seat (<em>bēma</em>, G968, the raised platform of judgment). The plurality and the universality (<em>pantes</em>) undercut the presumption of any individual\'s pre-judgment of another.</p>',
    "11": '<p><strong>γέγραπται γάρ</strong> — The citation is from Isa 45:23 (LXX), here blended with Isa 49:18. The perfect <em>gegraptai</em> (it stands written): the scriptural authority is invoked as permanent. <em>Zō egō, legei kyrios</em> — the divine oath formula ("As I live, says the Lord"): God\'s own life is the pledge. <strong>ἐμοὶ κάμψει πᾶν γόνυ καὶ πᾶσα γλῶσσα ἐξομολογήσεται τῷ θεῷ</strong> — every knee will bow, every tongue will confess. At Phil 2:10–11 Paul applies the same text to Jesus; here it grounds accountability to God as judge. The application is consistent: the one before whom every knee bows is the one before whose judgment seat all will stand.</p>',
    "12": '<p><strong>ἄρα οὖν ἕκαστος ἡμῶν περὶ ἑαυτοῦ λόγον δώσει τῷ θεῷ</strong> — <em>Ara oun</em> (therefore then): the logical conclusion from vv.10–11. <em>Logos dōsei</em> (will give account): the forensic idiom — rendering an accounting before a court. <em>Peri heautou</em> (about himself): the account is individual and personal. The implication: since each person must give account for himself, judging another\'s account in advance is a category error — it presumes standing the judge does not possess.</p>',
    "13": '<p><strong>μηκέτι οὖν ἀλλήλους κρίνωμεν</strong> — The hortatory subjunctive shifts to communal resolution: let us no longer judge one another. <strong>ἀλλὰ τοῦτο κρίνατε μᾶλλον</strong> — rather, decide (<em>krinate</em>, aorist imperative of <em>krinō</em>) this: a playful inversion of the prohibition, using the same verb. <strong>τὸ μὴ τιθέναι πρόσκομμα τῷ ἀδελφῷ ἢ σκάνδαλον</strong> — not to place a stumbling-block (<em>proskomma</em>, G4348) or a trap (<em>skandalon</em>, G4625, the trigger-stick of an animal trap, then metaphorically an occasion for moral failure).</p>',
    "14": '<p><strong>οἶδα καὶ πέπεισμαι ἐν κυρίῳ Ἰησοῦ ὅτι οὐδὲν κοινὸν δι᾽ ἑαυτοῦ</strong> — <em>Oida</em> (know) + <em>pepeismai</em> (perfect passive of <em>peithō</em>, to persuade — am fully persuaded, G3982): Paul asserts personal conviction at the highest level. <em>Koinos</em> (G2839, common/unclean) — in the ritual purity sense. The principle: nothing is unclean by its own nature (<em>di᾽ heautou</em>). <strong>εἰ μὴ τῷ λογιζομένῳ τι κοινὸν εἶναι, ἐκείνῳ κοινόν</strong> — but for the one who considers it unclean, it is unclean. <em>Logizomenō</em> (G3049, to reckon, count, consider): the act of personal moral reckoning determines the category for that person. The principle respects the primacy of conscience.</p>',
    "15": '<p><strong>εἰ γὰρ διὰ βρῶμα ὁ ἀδελφός σου λυπεῖται</strong> — <em>Brōma</em> (G1033, food) is the material object; <em>lypeō</em> (G3076, to grieve, distress) describes the effect on the brother. <strong>οὐκέτι κατὰ ἀγάπην περιπατεῖς</strong> — you are no longer walking according to love: <em>kata agapēn</em> (according to love) is the governing principle of conduct. <strong>μὴ τῷ βρώματί σου ἐκεῖνον ἀπόλλυε ὑπὲρ οὗ Χριστὸς ἀπέθανεν</strong> — the escalation is stark: destroying (<em>apollye</em>, G622) someone for whom Christ died — over food. The relative clause <em>hyper hou Christos apethanen</em> (for whom Christ died) grounds the prohibition in the infinite value of the person.</p>',
    "16": '<p><strong>μὴ βλασφημείσθω οὖν ὑμῶν τὸ ἀγαθόν</strong> — <em>Blasphēmeitō</em> (G987, spoken of as evil): the freedom of the strong, which is genuinely good (<em>to agathon</em>), must not become an occasion for the outsider\'s blasphemy. The "good" being blasphemed is the liberty in Christ; the behavior of the strong, if exercised without regard for the weak, turns a gift into a scandal.</p>',
    "17": '<p><strong>οὐ γάρ ἐστιν ἡ βασιλεία τοῦ θεοῦ βρῶσις καὶ πόσις</strong> — <em>Basileia tou theou</em> (kingdom of God): the governing rule of God in its present experiential expression. The kingdom\'s substance is not eating and drinking (<em>brōsis kai posis</em>) — not dietary and ritual practice. <strong>ἀλλὰ δικαιοσύνη καὶ εἰρήνη καὶ χαρὰ ἐν πνεύματι ἁγίῳ</strong> — <em>Dikaiosynē</em> (G1343, dl=4) here is behavioral/moral uprightness within the community, not the forensic justification of chs. 1–8; <em>eirēnē</em> (peace) is communal harmony; <em>khara</em> (joy) is the Spirit-produced delight. <em>En pneumati hagiō</em> (in the Holy Spirit): the Spirit is the sphere in which these qualities exist and the agent who produces them.</p>',
    "18": '<p><strong>ὁ γὰρ ἐν τούτῳ δουλεύων τῷ Χριστῷ εὐάρεστος τῷ θεῷ καὶ δόκιμος τοῖς ἀνθρώποις</strong> — <em>En toutō douleuōn</em> (serving in this — in righteousness, peace, and joy): the participle picks up the three nouns of v.17. <em>Euarestos tō theō</em> (pleasing to God, G2101) — the same word as 12:1\'s "acceptable/pleasing to God." <em>Dokimos tois anthrōpois</em> (G1384, approved by people — having passed the test): the life lived in the Spirit\'s fruits wins the approval of the human community as well as God.</p>',
    "19": '<p><strong>ἄρα οὖν τὰ τῆς εἰρήνης διώκωμεν</strong> — <em>Ara oun</em> + hortatory subjunctive: the conclusion drives to action. <em>Diōkō</em> (G1377, pursue, chase): the competitive-pursuit word recurs from 12:13. <em>Ta tēs eirēnēs</em> (the things of peace) and <em>ta tēs oikodomēs</em> (the things of building up/edification, G3619): two goal-objects to pursue. <em>Oikodomē</em> (building, edifice) used of community formation is a Pauline technical term for the constructive growth of the community.</p>',
    "20": '<p><strong>μὴ ἕνεκεν βρώματος κατάλυε τὸ ἔργον τοῦ θεοῦ</strong> — <em>Katalyō</em> (G2647, to tear down, demolish — the building-metaphor in reverse). The work of God (the community, the weak believer) is not to be demolished for food. <strong>πάντα μὲν καθαρά</strong> — all things are clean (the principle Paul agrees with). <strong>ἀλλὰ κακὸν τῷ ἀνθρώπῳ τῷ διὰ προσκόμματος ἐσθίοντι</strong> — but it is evil for the person who eats through a stumbling-block: the manner of eating that creates the stumbling-block for another is the evil. The freedom is real; the exercise that harms another is not.</p>',
    "21": '<p><strong>καλὸν τὸ μὴ φαγεῖν κρέα μηδὲ πιεῖν οἶνον μηδὲ ἐν ᾧ ὁ ἀδελφός σου προσκόπτει</strong> — The infinitives are articular (<em>to mē phagein</em>): the good thing is the concrete action of not eating meat, not drinking wine, not doing anything by which the brother stumbles. The list is practical — wine as well as meat were relevant to the Roman context (Diaspora Jewish practice varied on wine at Gentile tables). The conclusion states the norm positively: abstinence, when it prevents a sibling\'s fall, is good.</p>',
    "22": '<p><strong>σὺ πίστιν ἣν ἔχεις κατὰ σεαυτὸν ἔχε ἐνώπιον τοῦ θεοῦ</strong> — <em>Pistin hēn ekheis</em> (the faith/conviction you have): the strong person\'s liberty of conscience is a possession to be kept (<em>kata seauton</em>, between yourself and God, not paraded before the community). <strong>μακάριος ὁ μὴ κρίνων ἑαυτὸν ἐν ᾧ δοκιμάζει</strong> — blessed is the one who does not judge himself in what he approves: <em>dokimazō</em> (G1381, to test/approve). The blessing is for the person whose conscience (<em>pistis/conviction</em>) is settled enough that self-condemnation does not arise.</p>',
    "23": '<p><strong>ὁ δὲ διακρινόμενος ἐὰν φάγῃ κατακέκριται</strong> — <em>Diakrinomenos</em> (G1252, the one who doubts/wavers, hesitates between options): the wavering person who eats against their own scruple is condemned (<em>katakrinetai</em>, G2632, perfect passive: has been condemned and the condemnation stands). The condemnation is self-condemnation through conscience: <em>ὅτι οὐκ ἐκ πίστεως</em> — because not from faith/conviction. <strong>πᾶν δὲ ὃ οὐκ ἐκ πίστεως ἁμαρτία ἐστίν</strong> — everything not from faith is sin. Here <em>pistis</em> means the personal settled conviction that makes an action conscientiously permissible for the person doing it. The maxim is not about saving faith but about the relationship between conscience and action: acting against one\'s own conscience is sin, regardless of the objective permissibility of the act.</p>'
  }
}


def main():
    existing = load_comm('mkt-original', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-original', 'romans', existing)
    print('Romans 11–14 mkt-original written.')

if __name__ == '__main__':
    main()
